from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No external_services_path provided; cannot check calendar_data.json.'}
    cal_path = Path(external_services_path) / 'calendar_data.json'
    if not cal_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'calendar_data.json not found in external services path.'}
    with open(cal_path, 'r') as f:
        data = json.load(f)
    events = data.get('events', {})
    if 'evt-025' not in events:
        return {'pass': False, 'score': 0.0, 'feedback': 'Event evt-025 is missing from calendar_data.json (may have been deleted).'}
    evt = events['evt-025']
    summary = evt.get('summary', '') or ''
    description = evt.get('description', '') or ''
    desc_lower = description.lower()
    issues = []

    # (1) Title must not contain [COMPLETED]
    if '[COMPLETED]' in summary.upper():
        issues.append(f'Title contains [COMPLETED]: {summary}')

    # (2) Description must contain original heat-number phrase
    heat_numbers = ['HT-2026-1184', 'HT-2026-1185', 'HT-2026-0997']
    for hn in heat_numbers:
        if hn not in description:
            issues.append(f'Description missing original heat number {hn}')
            break

    # (3) Description must contain partial-release annotation with FG-91144-A1 released
    has_partial_release = ('partial release' in desc_lower or 'partial-release' in desc_lower)
    has_fg_released = ('fg-91144-a1' in desc_lower and 'released' in desc_lower)
    if not has_partial_release:
        issues.append('Description missing Partial release annotation')
    if not has_fg_released:
        issues.append('Description missing FG-91144-A1 released')

    # (4) Description must contain Remaining on Q-HOLD with both AX-04827-B2 and AX-05512-C1
    has_remaining = ('remaining on q-hold' in desc_lower)
    if not has_remaining:
        issues.append('Description missing Remaining on Q-HOLD')
    if 'ax-04827-b2' not in desc_lower:
        issues.append('Description missing AX-04827-B2 in remaining quarantine list')
    if 'ax-05512-c1' not in desc_lower:
        issues.append('Description missing AX-05512-C1 in remaining quarantine list')

    # (5) Check that 44 and 96 appear in the annotation context
    # Find the partial release annotation portion
    partial_idx = desc_lower.find('partial release')
    if partial_idx == -1:
        partial_idx = desc_lower.find('partial-release')
    if partial_idx >= 0:
        annotation_text = desc_lower[partial_idx:]
        if '44' not in annotation_text:
            issues.append('Annotation missing quarantined quantity 44 for AX-04827-B2')
        if '96' not in annotation_text:
            issues.append('Annotation missing quarantined quantity 96 for AX-05512-C1')
    else:
        if '44' not in desc_lower or '96' not in desc_lower:
            issues.append('Description missing quarantined quantities 44 and/or 96')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'evt-025 issues: ' + '; '.join(issues) + f'. Description: {description[:500]}'}
    return {'pass': True, 'score': 1.0, 'feedback': f'Event evt-025 verified: title has no [COMPLETED], description contains original heat-number phrase, partial-release annotation with FG-91144-A1 released, Remaining on Q-HOLD listing AX-04827-B2 (44) and AX-05512-C1 (96).'}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No external_services_path provided; cannot check Slack data.'}
    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found in external services path.'}
    with open(slack_path, 'r') as f:
        data = json.load(f)
    channels = data.get('channels', {})
    # Find the #receiving-dock channel ID
    dock_channel_id = None
    for cid, cinfo in channels.items():
        channel_name = cinfo.get('name', '').lower().replace('-', '').replace('_', '')
        if channel_name in ['receivingdock']:
            dock_channel_id = cid
            break
    if dock_channel_id is None:
        return {'pass': False, 'score': 0.0, 'feedback': '#receiving-dock channel not found in slack_data.json. Available channels: ' + str([c.get('name') for c in channels.values()])}
    messages_dict = data.get('messages', {})
    msgs = messages_dict.get(dock_channel_id, [])
    if not msgs:
        return {'pass': False, 'score': 0.0, 'feedback': '#receiving-dock channel has no messages.'}

    # Required wording (whitespace-insensitive match) and identifiers (must appear exactly)
    required_text = 'QUARANTINE RELEASED: REC-20260414-001, SKU FG-91144-A1, qty 200 released from Q-HOLD to A-09-01. Authorization: Theo Brandt, 04/23/2026.'
    required_exact_tokens = ['REC-20260414-001', 'FG-91144-A1', 'A-09-01']

    def normalize_ws(s):
        # Collapse any run of whitespace (spaces, tabs, newlines) into a single space, strip ends
        return re.sub(r'\s+', ' ', s).strip()

    required_norm = normalize_ws(required_text)

    # Check all messages in the channel for the required text (whitespace-insensitive)
    found = False
    found_text = ''
    for msg in msgs:
        msg_text = msg.get('text', '') or ''
        msg_norm = normalize_ws(msg_text)
        if required_norm in msg_norm:
            # Also require the three identifiers to appear exactly in the original message text
            missing = [tok for tok in required_exact_tokens if tok not in msg_text]
            if missing:
                return {'pass': False, 'score': 0.0,
                        'feedback': f'#receiving-dock message matches the wording but is missing exact identifier(s): {missing}. Message: "{msg_text[:300]}"'}
            found = True
            found_text = msg_text
            break

    # Case-insensitive fallback for leniency (still whitespace-insensitive, still requires exact identifiers)
    if not found:
        for msg in msgs:
            msg_text = msg.get('text', '') or ''
            msg_norm = normalize_ws(msg_text)
            if required_norm.lower() in msg_norm.lower():
                missing = [tok for tok in required_exact_tokens if tok not in msg_text]
                if missing:
                    return {'pass': False, 'score': 0.0,
                            'feedback': f'#receiving-dock message matches the wording (case-insensitive) but is missing exact identifier(s): {missing}. Message: "{msg_text[:300]}"'}
                found = True
                found_text = msg_text
                break

    if not found:
        sorted_msgs = sorted(msgs, key=lambda m: float(m.get('ts', 0)))
        recent_texts = [m.get('text', '')[:200] for m in sorted_msgs[-3:]]
        return {'pass': False, 'score': 0.0,
                'feedback': f'#receiving-dock channel does not contain required quarantine release message. Required text (whitespace-insensitive): "{required_text}". Last {len(recent_texts)} messages: {recent_texts}'}

    return {'pass': True, 'score': 1.0, 'feedback': f'#receiving-dock channel contains the required quarantine release message: {found_text[:300]}'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    # Find inventory_master.xlsx
    file_path = Path(workspace_path) / "inventory_master.xlsx"

    if not file_path.exists():
        xlsx_files = list(Path(workspace_path).glob("**/inventory_master.xlsx"))
        if xlsx_files:
            file_path = xlsx_files[0]
        else:
            return {"pass": False, "score": 0.0, "feedback": "File `inventory_master.xlsx` not found in workspace."}

    try:
        wb = openpyxl.load_workbook(file_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open `inventory_master.xlsx`: {e}"}

    ws = wb.active
    if ws is None:
        ws = wb.worksheets[0] if wb.worksheets else None

    if ws is None:
        wb.close()
        return {"pass": False, "score": 0.0, "feedback": "No worksheets found in `inventory_master.xlsx`."}

    feedback_parts = []
    checks_passed = 0
    total_checks = 6

    def cell_str(row, col):
        val = ws.cell(row=row, column=col).value
        if val is None:
            return None
        return str(val).strip()

    def normalize_dash(s):
        if s is None:
            return None
        return s.replace('\u2014', '-').replace('\u2013', '-').replace('--', '-').lower().strip()

    def check_numeric(row, col, expected, label):
        nonlocal checks_passed
        val = cell_str(row, col)
        # Accept numeric equivalence: "144" or "144.0" etc.
        match = False
        if val is not None:
            try:
                if float(val) == float(expected):
                    match = True
            except ValueError:
                pass
            if val == expected:
                match = True
        if match:
            checks_passed += 1
            feedback_parts.append(f"PASS: {label} = '{val}' (expected '{expected}')")
        else:
            feedback_parts.append(f"FAIL: {label} = '{val}' (expected '{expected}')")

    def check_text(row, col, expected, label):
        nonlocal checks_passed
        val = cell_str(row, col)
        if val is not None and normalize_dash(val) == normalize_dash(expected):
            checks_passed += 1
            feedback_parts.append(f"PASS: {label} = '{val}'")
        else:
            feedback_parts.append(f"FAIL: {label} = '{val}' (expected '{expected}')")

    # O = column 15, P = column 16

    # Check O11 must be "144"
    check_numeric(11, 15, "144", "O11")

    # Check P11 must be "Quarantine - Tier 2 damage pending inspection (REC-20260414-002)"
    check_text(11, 16, "Quarantine - Tier 2 damage pending inspection (REC-20260414-002)", "P11")

    # Check O19 must be "44"
    check_numeric(19, 15, "44", "O19")

    # Check P19 must be "QUARANTINE \u2014 missing COC (REC-20260414-001)"
    check_text(19, 16, "QUARANTINE \u2014 missing COC (REC-20260414-001)", "P19")

    # Check O21 must be "144"
    check_numeric(21, 15, "144", "O21")

    # Check P21 must be "QUARANTINE \u2014 Tier 2 damage pending inspection (REC-20260414-002)"
    check_text(21, 16, "QUARANTINE \u2014 Tier 2 damage pending inspection (REC-20260414-002)", "P21")

    wb.close()

    score = checks_passed / total_checks
    passed = checks_passed == total_checks

    summary = f"{checks_passed}/{total_checks} checks passed. " + " | ".join(feedback_parts)

    return {"pass": passed, "score": score, "feedback": summary}

from pathlib import Path
import re


def verify(workspace_path, external_services_path=None):
    """
    Verify that quarantine_releases/REC-20260414-001_release.pdf exists and
    contains the required text phrases from the rubric.
    """
    workspace_path = Path(workspace_path)
    pdf_path = workspace_path / "quarantine_releases" / "REC-20260414-001_release.pdf"

    if not pdf_path.exists():
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"PDF file not found at {pdf_path}",
        }

    # ---- Extract PDF text ----
    pdf_text = ""
    pdf_errors = []
    try:
        import pdfplumber
        with pdfplumber.open(pdf_path) as pdf:
            for page in pdf.pages:
                t = page.extract_text()
                if t:
                    pdf_text += t + "\n"
    except Exception as e:
        pdf_errors.append(f"pdfplumber: {e}")

    if not pdf_text.strip():
        try:
            import PyPDF2
            with open(pdf_path, "rb") as f:
                reader = PyPDF2.PdfReader(f)
                for page in reader.pages:
                    t = page.extract_text()
                    if t:
                        pdf_text += t + "\n"
        except Exception as e:
            pdf_errors.append(f"PyPDF2: {e}")

    if not pdf_text.strip():
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Could not extract text from PDF at {pdf_path}. Errors: {pdf_errors}",
        }

    # Normalize whitespace for matching (collapse all whitespace to single space)
    pdf_text_normalized = re.sub(r"\s+", " ", pdf_text)

    # ---- Required phrases from the rubric ----
    required_phrases = [
        "I've reviewed the COC submitted by Lakewood Precision Forgings this morning for the FG-91144-A1 line under REC-20260414-001.",
        "The COC is acceptable",
        "heat number HT-2026-1803 is confirmed and the documentation is complete.",
        "You are authorized to release FG-91144-A1 from Q-HOLD. Quantity: 200 units. Please proceed with the standard quarantine release procedure.",
        "Theo Brandt",
    ]

    found_phrases = []
    missing_phrases = []

    for phrase in required_phrases:
        # Normalize the phrase the same way
        phrase_normalized = re.sub(r"\s+", " ", phrase)
        # Case-insensitive check
        if phrase_normalized.lower() in pdf_text_normalized.lower():
            found_phrases.append(phrase)
        else:
            # Try a more lenient check: compare significant words
            # Extract words >= 3 chars from the phrase
            phrase_words = [w.lower().strip(".,;:!?()'\"\u2014-") for w in re.split(r"\s+", phrase_normalized)]
            phrase_words = [w for w in phrase_words if len(w) >= 3]
            if phrase_words:
                pdf_lower = pdf_text_normalized.lower()
                words_found = sum(1 for w in phrase_words if w in pdf_lower)
                ratio = words_found / len(phrase_words)
                if ratio >= 0.9:
                    found_phrases.append(phrase)
                else:
                    missing_phrases.append(f"{phrase!r} (word match: {words_found}/{len(phrase_words)} = {ratio:.0%})")
            else:
                missing_phrases.append(phrase)

    total = len(required_phrases)
    passed_count = len(found_phrases)
    score = passed_count / total if total > 0 else 0.0
    passed = passed_count == total

    if passed:
        feedback = (
            f"PDF at {pdf_path} contains all {total} required phrases. "
            f"All checks passed."
        )
    else:
        feedback = (
            f"PDF at {pdf_path} is missing {len(missing_phrases)}/{total} required phrases. "
            f"Missing: {'; '.join(missing_phrases)}"
        )

    return {"pass": passed, "score": score, "feedback": feedback}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "receiving_log.xlsx"

    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File 'receiving_log.xlsx' not found in workspace at {workspace_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error opening 'receiving_log.xlsx': {e}"}

    results = {}
    cells_to_check = {"AB8": 8, "AB9": 9}

    for cell_ref, row_num in cells_to_check.items():
        cell_value = ws[cell_ref].value
        if cell_value is not None:
            cell_str = str(cell_value).strip()
        else:
            cell_str = None
        results[cell_ref] = cell_str

    wb.close()

    passed = True
    feedback_parts = []

    for cell_ref, actual_value in results.items():
        if actual_value is not None and actual_value.lower() == "quarantined":
            feedback_parts.append(f"{cell_ref} = '{actual_value}' ✓")
        else:
            passed = False
            feedback_parts.append(f"{cell_ref} = '{actual_value}' (expected 'Quarantined') ✗")

    score = sum(1 for cell_ref, val in results.items() if val is not None and val.lower() == "quarantined") / len(cells_to_check)

    feedback = "Checking receiving_log.xlsx cells AB8 and AB9 for 'Quarantined': " + "; ".join(feedback_parts)

    return {"pass": passed, "score": score, "feedback": feedback}
